UPDATE public.recipes target
SET description=seed.description,
    ingredients=seed.ingredients,
    recipe_type=seed.recipe_type,
    discipline=seed.discipline,
    rarity=seed.rarity,
    base_dc=seed.base_dc,
    source=seed.source,
    tags=seed.tags,
    duration=seed.duration,
    use_text=seed.use_text,
    effect_text=seed.effect_text,
    formula_tags=seed.formula_tags,
    required_tags=seed.required_tags,
    secondary_tags=seed.secondary_tags,
    enhancer_tags=seed.enhancer_tags,
    output_quantity=seed.output_quantity,
    batch_quantity=seed.batch_quantity,
    ingredient_slots=seed.ingredient_slots,
    family_formula=seed.family_formula,
    alchemy_section=seed.alchemy_section,
    base_duration_seconds=seed.base_duration_seconds,
    base_duration_dice_count=seed.base_duration_dice_count,
    base_duration_die_size=seed.base_duration_die_size,
    base_duration_unit=seed.base_duration_unit,
    base_dice_count=seed.base_dice_count,
    base_die_size=seed.base_die_size,
    base_flat_bonus=seed.base_flat_bonus,
    base_uses=seed.base_uses,
    dice_purpose=seed.dice_purpose,
    effect_cadence=seed.effect_cadence,
    condition_riders=seed.condition_riders,
    cures_conditions=seed.cures_conditions,
    rider_save=seed.rider_save,
    rider_duration=seed.rider_duration,
    rider_repeat_save=seed.rider_repeat_save,
    grants_immunities=seed.grants_immunities,
    formula_family=seed.formula_family,
    theme_source=seed.theme_source,
    alchemy_group=seed.alchemy_group,
    template_key=seed.template_key,
    required_tags_any=seed.required_tags_any,
    tag_label=seed.tag_label,
    base_area_feet=seed.base_area_feet,
    area_shape=seed.area_shape,
    save_ability=seed.save_ability, updated_at=now()
FROM _alchemy_v9_recipe_seed seed
WHERE lower(target.name)=lower(seed.name)
  AND lower(coalesce(target.discipline,target.recipe_type,''))='alchemy';

INSERT INTO public.recipes (name, description, ingredients, recipe_type, discipline, rarity, base_dc, source, tags, duration, use_text, effect_text, formula_tags, required_tags, secondary_tags, enhancer_tags, output_quantity, batch_quantity, ingredient_slots, family_formula, alchemy_section, base_duration_seconds, base_duration_dice_count, base_duration_die_size, base_duration_unit, base_dice_count, base_die_size, base_flat_bonus, base_uses, dice_purpose, effect_cadence, condition_riders, cures_conditions, rider_save, rider_duration, rider_repeat_save, grants_immunities, formula_family, theme_source, alchemy_group, template_key, required_tags_any, tag_label, base_area_feet, area_shape, save_ability)
SELECT seed.name, seed.description, seed.ingredients, seed.recipe_type, seed.discipline, seed.rarity, seed.base_dc, seed.source, seed.tags, seed.duration, seed.use_text, seed.effect_text, seed.formula_tags, seed.required_tags, seed.secondary_tags, seed.enhancer_tags, seed.output_quantity, seed.batch_quantity, seed.ingredient_slots, seed.family_formula, seed.alchemy_section, seed.base_duration_seconds, seed.base_duration_dice_count, seed.base_duration_die_size, seed.base_duration_unit, seed.base_dice_count, seed.base_die_size, seed.base_flat_bonus, seed.base_uses, seed.dice_purpose, seed.effect_cadence, seed.condition_riders, seed.cures_conditions, seed.rider_save, seed.rider_duration, seed.rider_repeat_save, seed.grants_immunities, seed.formula_family, seed.theme_source, seed.alchemy_group, seed.template_key, seed.required_tags_any, seed.tag_label, seed.base_area_feet, seed.area_shape, seed.save_ability
FROM _alchemy_v9_recipe_seed seed
WHERE NOT EXISTS (
  SELECT 1 FROM public.recipes target
  WHERE lower(target.name)=lower(seed.name)
    AND lower(coalesce(target.discipline,target.recipe_type,''))='alchemy'
);
COMMIT;
